<?php
namespace App\Domain\Equipment;use App\Models\Item;use InvalidArgumentException;
final class HandItemConfigurationValidator{const LEGACY_MAIN_HAND_ONLY='legacy_main_hand_only';public function classify(Item $item){if($item->equipment_type!==EquipmentType::WEAPON){if($item->hand_requirement!==null||$item->equipment_family!==null)throw new InvalidArgumentException('Los objetos que no son de mano no pueden tener requisito ni familia de mano.');return null;}if($item->hand_requirement===null&&$item->equipment_family===null)return self::LEGACY_MAIN_HAND_ONLY;if($item->hand_requirement===null||$item->equipment_family===null)throw new InvalidArgumentException('Los objetos de mano deben indicar requisito y familia.');$requirement=HandRequirement::assertValid($item->hand_requirement);$family=EquipmentItemFamily::assertValid($item->equipment_family);if(in_array($requirement,[HandRequirement::ONE_HAND,HandRequirement::TWO_HAND],true)&&!EquipmentItemFamily::isWeapon($family))throw new InvalidArgumentException('Una arma de una o dos manos requiere una familia de arma.');if($requirement===HandRequirement::OFF_HAND_ONLY&&!EquipmentItemFamily::isOffHandSupport($family))throw new InvalidArgumentException('Un objeto solo de mano secundaria requiere una familia secundaria.');return$requirement;}public function isLegacy(Item $item){return$this->classify($item)===self::LEGACY_MAIN_HAND_ONLY;}}
